CREATE OR REPLACE TRIGGER trg_before_insert_emp
BEFORE INSERT ON employee
FOR EACH ROW
BEGIN
 -- Auto-generate employee ID if not provided
 IF :NEW.emp_id IS NULL THEN
 SELECT 'EMP' || TO_CHAR(emp_seq.NEXTVAL) 
 INTO :NEW.emp_id 
 FROM DUAL;
 END IF;
 -- Set creation timestamp
 :NEW.created_date := SYSDATE;
 :NEW.created_by := USER;
END;
/

-- Statement-level trigger to prevent deletions during business hours
CREATE TRIGGER trg_no_delete_hours
BEFORE DELETE ON employee
BEGIN
 IF TO_CHAR(SYSDATE, 'HH24') BETWEEN 9 AND 17 THEN
 RAISE_APPLICATION_ERROR(-20001, 
 'Cannot delete employees during business hours (9 AM - 5 PM)');
 END IF;
END;
/

CREATE OR REPLACE TRIGGER trg_compound_emp
FOR UPDATE OF salary ON employee
COMPOUND TRIGGER
 -- Declarative section - persists across timing points
 TYPE t_salaries IS TABLE OF employee.salary%TYPE INDEX BY PLS_INTEGER;
 v_salaries t_salaries;
 v_count INTEGER := 0;

 BEFORE STATEMENT IS
 BEGIN
 v_count := 0;
 END BEFORE STATEMENT;

 BEFORE EACH ROW IS
 BEGIN
 v_count := v_count + 1;
 v_salaries(v_count) := :NEW.salary;
 END BEFORE EACH ROW;

 AFTER STATEMENT IS
 BEGIN
 -- Log total salary changes after statement completes
 DBMS_OUTPUT.PUT_LINE('Total rows processed: ' || v_count);
 END AFTER STATEMENT;
END trg_compound_emp;
/
